"use client";

import { useQuery } from "@tanstack/react-query";
import { getRestaurants, PublicRestaurant } from "@/lib/api";
import { RestaurantCard } from "./RestaurantCard";
import { Icon } from "@/components/ui/Icon";
import { OrderMode } from "@/stores/orderModeStore";

interface RestaurantListProps {
  mode: OrderMode;
  onSelectRestaurant: (restaurant: PublicRestaurant) => void;
}

export function RestaurantList({ mode, onSelectRestaurant }: RestaurantListProps) {
  const apiMode = mode === "delivery" ? "delivery" : mode === "takeaway" ? "takeaway" : undefined;

  const { data: restaurants = [], isLoading, error } = useQuery({
    queryKey: ["restaurants", apiMode],
    queryFn: () => getRestaurants(apiMode),
  });

  if (isLoading) {
    return (
      <div className="space-y-3">
        {Array.from({ length: 3 }).map((_, i) => (
          <div
            key={i}
            className="bg-white rounded-xl p-4 border border-border animate-pulse"
          >
            <div className="flex gap-4">
              <div className="w-16 h-16 rounded-lg bg-gray-200" />
              <div className="flex-1 space-y-2">
                <div className="h-5 bg-gray-200 rounded w-1/2" />
                <div className="h-4 bg-gray-200 rounded w-3/4" />
                <div className="h-4 bg-gray-200 rounded w-1/3" />
              </div>
            </div>
          </div>
        ))}
      </div>
    );
  }

  if (error) {
    return (
      <div className="text-center py-8">
        <Icon name="error" size={48} className="text-red-400 mx-auto mb-3" />
        <p className="text-muted">Не удалось загрузить рестораны</p>
      </div>
    );
  }

  if (restaurants.length === 0) {
    return (
      <div className="text-center py-8">
        <Icon name="store" size={48} className="text-gray-300 mx-auto mb-3" />
        <p className="text-muted">
          {mode === "delivery"
            ? "Нет ресторанов с доставкой"
            : mode === "takeaway"
            ? "Нет ресторанов с самовывозом"
            : "Нет доступных ресторанов"}
        </p>
      </div>
    );
  }

  return (
    <div className="space-y-3">
      <h3 className="text-sm font-medium text-muted">
        {mode === "delivery"
          ? "Рестораны с доставкой"
          : mode === "takeaway"
          ? "Рестораны с самовывозом"
          : "Все рестораны"}
      </h3>
      {restaurants.map((restaurant) => (
        <RestaurantCard
          key={restaurant.id}
          restaurant={restaurant}
          onSelect={onSelectRestaurant}
          showDeliveryFee={mode === "delivery"}
        />
      ))}
    </div>
  );
}
