"use client";

import { Icon } from "@/components/ui/Icon";
import { useOrderModeStore, OrderMode } from "@/stores/orderModeStore";

interface OrderModeSelectorProps {
  onModeSelect?: (mode: OrderMode) => void;
}

const modes: { id: OrderMode; label: string; icon: string; description: string }[] = [
  {
    id: "delivery",
    label: "Доставка",
    icon: "delivery_dining",
    description: "Доставим к вашей двери",
  },
  {
    id: "dinein",
    label: "В ресторане",
    icon: "restaurant",
    description: "Заказ за столиком",
  },
  {
    id: "takeaway",
    label: "С собой",
    icon: "takeout_dining",
    description: "Заберите сами",
  },
];

export function OrderModeSelector({ onModeSelect }: OrderModeSelectorProps) {
  const { mode, setMode } = useOrderModeStore();

  const handleModeSelect = (selectedMode: OrderMode) => {
    setMode(selectedMode);
    onModeSelect?.(selectedMode);
  };

  return (
    <div className="space-y-4">
      <h2 className="text-lg font-semibold text-foreground text-center">
        Как вы хотите заказать?
      </h2>
      <div className="grid grid-cols-3 gap-3">
        {modes.map((m) => (
          <button
            key={m.id}
            onClick={() => handleModeSelect(m.id)}
            className={`flex flex-col items-center p-4 rounded-xl border-2 transition-all ${
              mode === m.id
                ? "bg-orange-50 border-orange-500 text-orange-600"
                : "bg-white border-gray-200 text-gray-600 hover:border-orange-300 hover:bg-orange-50/50"
            }`}
          >
            <Icon
              name={m.icon}
              size={32}
              className={mode === m.id ? "text-orange-500" : "text-gray-400"}
            />
            <span className="mt-2 text-sm font-medium">{m.label}</span>
          </button>
        ))}
      </div>
    </div>
  );
}
