"use client";

import { Icon } from "@/components/ui/Icon";
import { Badge } from "@/components/ui/Badge";
import type { PublicRestaurant } from "@/lib/api";
import { getImageUrl } from "@/lib/api";

interface RestaurantCardProps {
  restaurant: PublicRestaurant;
  onSelect: (restaurant: PublicRestaurant) => void;
  showDeliveryFee?: boolean;
}

export function RestaurantCard({
  restaurant,
  onSelect,
  showDeliveryFee = false,
}: RestaurantCardProps) {
  const formatPrice = (price: number) => {
    return new Intl.NumberFormat("ru-RU").format(price);
  };

  return (
    <button
      onClick={() => onSelect(restaurant)}
      className="w-full bg-white rounded-xl p-4 border border-border hover:border-orange-300 hover:shadow-md transition-all text-left"
    >
      <div className="flex gap-4">
        {/* Logo */}
        <div className="w-16 h-16 rounded-lg bg-orange-100 flex items-center justify-center overflow-hidden flex-shrink-0">
          {restaurant.logoUrl ? (
            <img
              src={getImageUrl(restaurant.logoUrl) || ""}
              alt={restaurant.name}
              className="w-full h-full object-cover"
            />
          ) : (
            <Icon name="restaurant" size={28} className="text-orange-400" />
          )}
        </div>

        {/* Info */}
        <div className="flex-1 min-w-0">
          <h3 className="font-semibold text-foreground truncate">
            {restaurant.name}
          </h3>

          {restaurant.description && (
            <p className="text-sm text-muted line-clamp-1 mt-0.5">
              {restaurant.description}
            </p>
          )}

          {restaurant.address && (
            <div className="flex items-center gap-1 text-xs text-muted mt-1">
              <Icon name="location_on" size={14} className="flex-shrink-0" />
              <span className="truncate">{restaurant.address}</span>
            </div>
          )}

          {/* Tags */}
          <div className="flex flex-wrap gap-1 mt-2">
            {restaurant.deliveryEnabled && (
              <Badge variant="default" size="sm">
                <Icon name="delivery_dining" size={12} className="mr-1" />
                Доставка
              </Badge>
            )}
            {restaurant.takeawayEnabled && (
              <Badge variant="default" size="sm">
                <Icon name="takeout_dining" size={12} className="mr-1" />
                Самовывоз
              </Badge>
            )}
            {restaurant.onlinePaymentAvailable && (
              <Badge variant="success" size="sm">
                <Icon name="credit_card" size={12} className="mr-1" />
                Онлайн
              </Badge>
            )}
          </div>
        </div>

        {/* Delivery fee */}
        {showDeliveryFee && restaurant.deliveryEnabled && (
          <div className="flex flex-col items-end justify-center flex-shrink-0">
            <span className="text-xs text-muted">Доставка</span>
            <span className="font-semibold text-orange-500">
              {restaurant.deliveryFee > 0
                ? `${formatPrice(restaurant.deliveryFee)} TJS`
                : "Бесплатно"}
            </span>
          </div>
        )}
      </div>
    </button>
  );
}
